package policy

// PolicyConfig holds configuration for admission policy checks.
type PolicyConfig struct {
	// DenyPrivileged prevents containers from running in privileged mode
	DenyPrivileged bool
	// DenyHostNetwork prevents pods from using the host network namespace
	DenyHostNetwork bool
	// RequireResourceLimits enforces that all containers have CPU and memory limits
	RequireResourceLimits bool
	// RequireSecurityContext enforces security context settings
	RequireSecurityContext bool
}

// PolicyViolation represents a single policy check failure.
type PolicyViolation struct {
	// Policy is the name of the policy that was violated
	Policy string
	// Container is the name of the container that violated the policy (if applicable)
	Container string
	// Message is a human-readable description of the violation
	Message string
}

// DefaultPolicyConfig returns a PolicyConfig with all policies enabled.
func DefaultPolicyConfig() *PolicyConfig {
	return &PolicyConfig{
		DenyPrivileged:        true,
		DenyHostNetwork:       true,
		RequireResourceLimits: true,
		RequireSecurityContext: true,
	}
}

